var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"지하수로에서 <color=#ffd34c>그것</color>을 목격한 뒤로 며칠이 지났지만.","JPN":"地下水路で<color=#ffd34c>アレ</color>を目撃してから何日も過ぎたけど。","ENG":"It has been several days since we witnessed <color=#ffd34c>it</color> in the underground waterway.","TWN":"在下水道中看到<color=#ffd34c>那個</color>以後已經過了好幾天。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"우리 둘 다 그 일을 쉽게 입에 담을 수 없었다.","JPN":"私たちはその話を簡単に口にすることができなかった。","ENG":"Neither of us could get ourselves to talk about it.","TWN":"我們二個人都不敢輕易提起這件事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 그렇다고 그날 있었던 일을 계속 외면할 수는 없었기에.","JPN":"でも、だからってあの日のことをずっと黙っているわけにもいかないから。","ENG":"However, we could not keep ignoring what happened that day.","TWN":"但即便如此，也不能繼續假裝視而不見。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"앤이 먼저 이야기를 꺼냈다.","JPN":"アンが先に話を切り出した。","ENG":"So Ann brought it up first.","TWN":"於是安妮先起了頭。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서 이제 어떻게 할 거야?","JPN":"それで、これからどうする？","ENG":"So, what are you gonna do now?","TWN":"所以你現在打算怎麼辦？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"무슨 뜻이야……?","JPN":"どういうこと……？","ENG":"What do you mean...?","TWN":"什麼意思……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"네가 그랬잖아. 꿈 속에서 로젠탈에 끔찍한 일이 벌어지는 걸 봤다고.","JPN":"あなたが言ったでしょ？　夢の中でローゼンタールにひどいことが起きるのを見たって。","ENG":"You said you saw something terrible happen to Rosenthal in your dreams.","TWN":"你不是說過，在夢裡看到羅森泰發生了可怕的事情。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그리고 그걸 막고 싶다고 했지.","JPN":"そしてそれを止めたいって。","ENG":"And you said you wanted to prevent it.","TWN":"還說要阻止它。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"응…….","JPN":"うん……","ENG":"Yeah...","TWN":"嗯……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"나도 처음에는 별 생각 없이 알겠다고 했는데.","JPN":"私も最初は何も考えずに了承したけど……","ENG":"I said yes without much thought at first.","TWN":"我剛開始說的時候也沒多想。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리가 생각했던 것보다 문제가 훨씬 심각한 것 같아.","JPN":"私たちが思っているより、事態はずっと深刻みたい。","ENG":"But I think it's much more serious than we thought.","TWN":"但問題好像比我們想像的要嚴重得多。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서 말인데, 이브…….","JPN":"それでだけど、イヴ……","ENG":"So I was thinking, Eve...","TWN":"所以說，伊芙……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"나랑 여기서 튀자.","JPN":"私とここから逃げよう。","ENG":"Let's run away.","TWN":"跟我一起跑吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리 둘만이라면 어떻게든 도망칠 수 있을 거야.","JPN":"私たち二人だけなら、頑張れば逃げられるよ。","ENG":"If it's just us two, we should be able to run away somehow.","TWN":"只要有我們二個人，無論如何都能逃走。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤, 역시 우연이 아닐까?","JPN":"アン、やっぱり偶然じゃないかな？","ENG":"Ann, maybe it was a coincidence after all.","TWN":"會不會是偶然呢，安妮？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐라고?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그, 그렇지만…… 테오도라 수녀님도, 이곳의 친구들 동생들…….","JPN":"で、でも……テオドラさんも、ここのみんなも……","ENG":"B-but... Sister Theodora and our friends here...","TWN":"可，可是……狄奧朵拉修女，在這裡的大家，弟弟妹妹們……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"떠오르지는 않지만, 언니 오빠들도 다 좋은 사람들이었다고 생각해.","JPN":"覚えてないけど、お姉さんとお兄さんもみんないい人だったと思う。","ENG":"and, I can't remember, but even the older kids here. I think they were all good people.","TWN":"雖然想不起來，但是我覺得哥哥姊姊們都是好人。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以說……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이 멍청아! 생각 좀 해 봐!","JPN":"このバカ！　考えてみてよ！","ENG":"You dummy! Think!","TWN":"你這個笨蛋！你想想啊！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"네 능력으로 직접 보육원에 있던 물건을 통해서 지하수로를 봤잖아!","JPN":"あなたの能力で、保育園のガラクタを通して地下水路を見たじゃない！","ENG":"You saw the underground waterway through the object that was at the orphanage! With your ability!","TWN":"你用你的能力，透過育幼院裡大家留下的東西看到了下水道！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"하필 그 지하수로에 침식체가 살고 있었어! 이게 잘도 우연이겠다!?","JPN":"よりによってその地下水路に侵食体が住んでたんだよ！　これが本当に偶然だと思う！？","ENG":"And there was a C.O. in the underground waterway! Does that sound like a coincidence to you?!","TWN":"但偏偏那個下水道裡住著侵蝕體！這能是偶然嗎？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"너도 꿈속에서 그 괴물을 봤다면서!","JPN":"あなたも夢であの化け物を見たじゃない！","ENG":"You saw that monster in your dreams too!","TWN":"你不是說在夢裡也看到了那個怪物嗎！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그게 전부가 아니야!","JPN":"それだけじゃないよ！","ENG":"And that's not all!","TWN":"而且！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리는 그곳에서 성황청에서 온 파견 사제랑 검은 옷의 남자가 만나는 것도 봤어!","JPN":"私たちはあそこで聖皇庁から来た派遣司祭と黒い服の男が会ってるのも見たんだよ！","ENG":"We also saw the missionary priest from the Holy Curia meet with the man in black clothing!","TWN":"我們在那裡還看到聖皇廳的司祭和黑衣男在密會！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그 두 사람은 그 침식체들을 보고도 아무렇지도 않았다고! 마치 알고 있었던 것처럼!","JPN":"あの二人は、あの侵食体たちを見ても全く動じてなかった！　まるで初めから知ってたみたいに！","ENG":"Those two weren't fazed by the C.O.s at all! Like they were aware of it!","TWN":"他們二個看到那些侵蝕體也毫不在意！就好像本就知道一樣！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그건 이 보육원의 배후에 우리가 모르는 무언가가 연관되어 있다는 뜻이겠지.","JPN":"それは、この保育園の背後に私たちの知らない秘密があるってことだよ。","ENG":"That means there is something behind this orphanage that we don't know about.","TWN":"這就表示育幼院的背後有我們不知道的東西。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"여길 나간 사람들은 진작에 침식체 뱃속에 있을지도 모른다고!","JPN":"ここから出た人たちは、とっくにあの侵食体のお腹に入ってるかもしれない！","ENG":"The people who left might have ended up inside the C.O.'s belly!","TWN":"離開這裡的人可能早就已經在侵蝕體肚子裡了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그, 그럼……!","JPN":"じゃ、じゃあ……！","ENG":"Th-then...!","TWN":"那，那……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"나한테 인형을 준…… 그 사람을, 우리는 왜 기억하지 못하는 거야?","JPN":"私にぬいぐるみをくれた……あの人を、どうして私たちは覚えてないの？","ENG":"Why... Why can't we remember the person who gave me the doll?","TWN":"送我娃娃的……那個人，我們為什麼不記得了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"항상 우리가 굶지 않도록 이것저것 챙겨줬던, 그런 사람이었어…….","JPN":"いつも私たちがお腹を空かないよう気遣ってくれる、そんな人だった……","ENG":"It was someone who took care of us so we didn't starve...","TWN":"為了不讓我們餓肚子，總是照顧著我們……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"잔소리가 심한 편이었지만…… 그것도 다 우리를 생각해서 해준 말이었고.","JPN":"本当に口うるさかったけど……それも全部、私たちを思っての言葉だった。","ENG":"They would nag us a lot... but, it was all in our best interests.","TWN":"雖然喜歡嘮叨……但那也是為了我們著想才說的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리는 진짜 가족도 아니었는데, 기억 속 그 사람은 우리를 진짜 동생처럼 생각했으니까.","JPN":"本当の家族じゃなくても、記憶の中のあの人は私たちのことを妹みたいに可愛がってくれてたから。","ENG":"We weren't actually related, but the person in my memory treated us like real sisters.","TWN":"雖然不是真正的親人，但記憶中的那個人，卻把我們當成了真正的妹妹。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤은 정말로 하나도 떠오르지 않는 거야?","JPN":"アンは本当に何も覚えてないの？","ENG":"You really can't remember anything, Ann?","TWN":"安妮真的什麼都想不起來了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L4_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"……몰라.","JPN":"……わかんない。","ENG":"...No.","TWN":"……我不知道。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤의 말대로, 언니 오빠들이 침식체한테 잡아먹혔다고 해도…….","JPN":"アンの言うとおり、お姉さんたちが侵食体に食べられてたとしても……","ENG":"Like you said, even if the older kids were eaten by C.O.s...","TWN":"就算安妮說對了，哥哥姊姊們被侵蝕體吃掉了……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리가 언니, 오빠들을 기억하지 못하는 건 이상한 일이잖아, 안 그래?","JPN":"私たちがあの人たちのことを覚えてないなんて、おかしいでしょう？　違う？","ENG":"it's weird that we can't remember them, right?","TWN":"但我們不記得哥哥姊姊了也很奇怪，不是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"좋아, 나간 퇴소자들이 어떻게 됐는지 조금 만 더 조사해보자.","JPN":"よし、ここから出た人たちがどうなったのか、もうちょっとだけ調べてみよう。","ENG":"Fine. Let's investigate a little more about what happened to the people who left the orphanage.","TWN":"好吧，那我們再調查一下離開的人都怎麼樣了吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"네 능력이라면, 아마도 할 수 있을 거야.","JPN":"あなたの能力なら、たぶんできるはずだよ。","ENG":"It should be possible with your ability.","TWN":"以你的能力，也許能做到。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"대신 이 보육원이 침식체들과 연관되어 있다는 게 밝혀지면 진짜로 여길 뜨는 거야?","JPN":"その代わり、この保育園が侵食体と関係があることがわかったら、絶対にここから逃げること。","ENG":"But if we find out that this orphanage has something to do with C.O.s, we have to leave.","TWN":"但是，如果發現這個育幼院與侵蝕體有關，就真的要離開這裡喔？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"알겠지?","JPN":"わかった？","ENG":"Okay?","TWN":"明白了吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……응. 고마워, 앤.","JPN":"……うん。ありがとう、アン。","ENG":"...Okay. Thanks, Ann.","TWN":"……嗯，謝謝你，安妮。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"좋아……. 아무도 없네.","JPN":"よし……誰もいないね。","ENG":"Good... There's no one here.","TWN":"很好……一個人都沒有。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"애, 앤! 여긴 테오도라 수녀님의 방이잖아! 원생들은 출입 금지라고!","JPN":"アン！　ここはテオドラさんの部屋じゃない！　院生は出入り禁止だよ！","ENG":"A-Ann! This is Sister Theodora's room! We aren't allowed in here!","TWN":"安，安妮！這裡是狄奧朵拉修女的房間！小孩子是不能進來的！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"무슨 소리야. 조사를 시작하려면 당연히 여기부터 해야지.","JPN":"何言ってるの。調査を始めるなら、当然ここからでしょ。","ENG":"What are you talking about? If we're going to investigate, we have to start here.","TWN":"說什麼呢。如果要開始調查，當然要從這裡開始。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"여길 나간 사람들이 어떻게 됐는지 알고 싶다면서?","JPN":"ここを出た人たちがどうなったのか知りたいんじゃなかった？","ENG":"I thought you wanted to know what happened to the people who left the orphanage, no?","TWN":"你不是想知道離開這裡的人怎麼樣了嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그건 그렇지만…….","JPN":"それはそうだけど……","ENG":"Yeah, but...","TWN":"是這樣沒錯……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그럼 잠자코 들어가기나 해.","JPN":"じゃあ、大人しく入りなさいよ。","ENG":"Then just go in.","TWN":"那你還是乖乖地進來吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"어때, 이브? 뭔가 떠오르는 게…… ","JPN":"イヴ、どう？　何か見えた…… ","ENG":"Eve? Can you see anything?","TWN":"怎麼樣，伊芙？有沒有想起什麼……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이브?","JPN":"イヴ？","ENG":"Eve?","TWN":"伊芙？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아, 아아……!","JPN":"あ、ああ……！","ENG":"Ah, aaaah...!","TWN":"啊，啊啊……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"하아, 하아, 우으윽……!","JPN":"はぁ、はぁ、うううっ……！","ENG":"*Huff... Huff...* Ugh...!","TWN":"哈啊，哈啊，呃呃……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이브! 괜찮아?","JPN":"イヴ！　大丈夫？","ENG":"Eve! Are you okay?","TWN":"伊芙！你沒事吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"으으, 으아아……!","JPN":"うう、あああ……！","ENG":"Ngh... Aaah...!","TWN":"呃，呃啊啊啊……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"어때, 여기서 뭔가를 봤구나?","JPN":"どうしたの？　何か見えたんだよね？","ENG":"You saw something, didn't you?","TWN":"你在這裡看到什麼了吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"우으으…… 가면 쓴 사람들…… 수녀님.","JPN":"ううう……仮面を被った人たち……シスター。","ENG":"Nghh... People wearing masks... and Sister.","TWN":"呃啊啊……戴面具的人……修女。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그러더니…… 아이들이 괴물한테…… 우욱!","JPN":"それで……子どもたちが化け物に……うぅぐ！","ENG":"And…the children... the monster is... eating... Uugh!","TWN":"然後……孩子們被怪物……唔！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"잠깐만, 이브! 누가 오는 것 같아!","JPN":"待って、イヴ！　誰か来た！","ENG":"Wait, Eve! Someone's coming!","TWN":"等一下，伊芙！好像有人來了！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"으윽……!","JPN":"ううっ……！","ENG":"Ngh...!","TWN":"呃呃……！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤, 나 너무 아파. 속이 안 좋아…….","JPN":"アン、私、気分が悪い……","ENG":"Ann, I feel sick. I feel so sick...","TWN":"安妮，好痛，我肚子不舒服……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"아, 안 되겠어! 이브가 정신을 못 차리잖아?","JPN":"だ、ダメだ！　イヴがまともに動けない。","ENG":"O-oh no! Eve can't get it together!","TWN":"不，不行了！伊芙好像要暈過去了？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이러다간 들키겠어!","JPN":"このままじゃ見つかる！","ENG":"They're gonna catch us!","TWN":"這樣下去會被發現的！"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이쪽으로 오시죠. 조용한 방으로 모시겠습니다.","JPN":"こちらへどうぞ。静かなお部屋にご案内します。","ENG":"This way. Let us talk somewhere quiet.","TWN":"這邊請，我帶你去安靜的房間。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"먼 곳까지 오시느라 고생이 많으셨을 텐데, 차라도 한 잔 내올까요?","JPN":"わざわざここまで足をお運びいただいたのですから、お茶でもいかがです？","ENG":"You've traveled far to get here. Would you like a cup of tea?","TWN":"遠道而來辛苦了，需要給你倒杯茶嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"미안하지만 차는 사양하지. 시간이 별로 없거든.","JPN":"悪いが、お茶は遠慮しよう。あまり時間がないのでね。","ENG":"I'm sorry, but I have to refuse. I don't have much time.","TWN":"抱歉，茶就不需要了，因為沒多少時間了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"바로 본론으로 들어가도 괜찮겠나?","JPN":"本題に入ってもいいかな？","ENG":"Do you mind if I get straight to the point?","TWN":"你不介意我直接進入正題吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"후후, 학부장님께서는 여전히 동분서주하시느라 바쁘시군요.","JPN":"ふふ、学部長は相変わらずお忙しいお方ですね。","ENG":"Haha, I see you're still busy running from place to place.","TWN":"呵呵，院長還是東奔西走很忙碌啊。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"본론이라 하시면, 역시 발주에 관한 문제인가요?","JPN":"本題ということは、やはり発注に関する問題でしょうか？","ENG":"I assume the point is the issue with the order that was put in?","TWN":"說到正題，應該是關於訂貨的問題吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이야기가 빠르군.","JPN":"話が早いな。","ENG":"Correct.","TWN":"看來你也很直接。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그때가 다가오고 있네. 가능한 빨리 최고 품질의 그릇이 필요해.","JPN":"あの時が近づいている。なるべく早く、最高品質の器が必要なのだ。","ENG":"It's almost time. We need a vessel of the best quality, as fast as possible.","TWN":"那我就直說了，那個時候就要到了，我需要最高品質的器皿，越快越好。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"……학부장님?","JPN":"……学部長？","ENG":"...Sir?","TWN":"……院長？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"저희 역시 영원불멸하실 어머니를 위해 헌신을 다하고 있습니다만.","JPN":"私たちもまた、永遠不滅である母のために身を捧げておりますが……","ENG":"We are also serving to our best ability toward our immortal Mother.","TWN":"我們都在為永垂不朽的母親獻身。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"아시다시피 그릇의 품질을 결정하는 건 어머니의 은총이랍니다.","JPN":"ご存じのとおり、器の品質を決めるのは母の恩寵です。","ENG":"As you are aware, it is our Mother's blessing that determines the quality of the vessel.","TWN":"你也知道，決定器皿品質的是母親的恩賜。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇기에 각지에서 모은 성배 후보를 지켜본 뒤, 꼼꼼히 테스트를 거칠 수밖에 없는 것이지요.","JPN":"ですので各地から集めた聖杯の候補を見守り、抜かりのなくテストをするしかありません。","ENG":"That is why we must conduct tests under scrutiny after observing the potential Holy Grails we've collected from various places.","TWN":"因此，在觀察從各地收集的聖杯候選後，還需要仔細地進行測驗。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"내 말 뜻을 이해하지 못한 모양이군.","JPN":"私の話を理解できなかったようだな。","ENG":"It seems like you failed to understand my point.","TWN":"看樣子你還不明白我的意思。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"나는 <color=#ffd34c>가능한 빨리</color> 최고 품질의 그릇이 필요하다고 했네.","JPN":"私は<color=#ffd34c>なるべく早く</color>最高品質の器が必要だと言ったのだ。","ENG":"I said I needed a vessel of the best quality <color=#ffd34c>as fast as possible</color>.","TWN":"我說的是<color=#ffd34c>越快越好</color>。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"기관의 사냥개가 냄새를 맡았어. 언제 이곳에 닥쳐도 이상하지 않지.","JPN":"機関の猟犬に気付かれた。いつここに押し掛けられてもおかしくない。","ENG":"The Institution's hound caught the scent of us. They can ambush this place at any time.","TWN":"機關裡的獵犬察覺到了，不管什麼時候找到這裡都不奇怪。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"의식을 제때 맞추려면 준비를 서둘러야 할 거야.","JPN":"儀式に間に合わせるためには、準備を急がねばならない。","ENG":"The preparation needs to be rushed for the ritual to start on time.","TWN":"要想及時舉辦儀式，就得抓緊時間準備。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Acknowledged.","TWN":"我知道了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"지금부터 투여량을 늘린다면, 어떻게든 원하시는 결과물을 보여드릴 수 있을 것 같군요.","JPN":"今から投与量を増やせば、お望みの結果をお見せできると思います。","ENG":"If we increase the dose going forward, we should be able to get some results to your liking.","TWN":"如果從現在開始增加劑量，無論如何都應該可以給你呈現你想要的結果。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"However...","TWN":"只是……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"파편 문제라면 너무 걱정하지 말게. 그건 우리측에서 어떻게든 해줄 테니까.","JPN":"破片の問題ならあまり心配するな。それはこちらでなんとかしてやろう。","ENG":"Don't worry about the Fragment. We will do something about it, one way or another.","TWN":"如果是碎片問題的話，就不要太擔心了。那個我們無論如何都會弄到。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"감사합니다.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그럼 부디 납품에 차질이 없길 바라겠네, 테오도라.","JPN":"では、どうか納品の日程に狂いがないことを祈るとしよう、テオドラ。","ENG":"Then, I sincerely hope there won't be any issues on delivering the order, Theodora.","TWN":"希望你們交貨的時候不會有任何差池，狄奧朵拉。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"네, 명심하겠습니다. 제임스 고고학부장님.","JPN":"はい、肝に銘じます。ジェームス考古学部長。","ENG":"Yes. Understood, Professor James.","TWN":"好，我記住了。詹姆斯考古學教授。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"아, 그렇지.","JPN":"ああ、そうだ。","ENG":"Oh, right.","TWN":"啊，對了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"자네에게 맡겨 두었던 물건은 내가 다시 가져가겠네.","JPN":"君に預けておいたものは、私が持っていくよ。","ENG":"I'll be taking the object I previously left with you.","TWN":"存放在你這裡的東西，我要再拿回去。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이, 이이……!","JPN":"この……この……！","ENG":"Why, you...!","TWN":"哼，哼……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이 노망난 노친네가 어딜 뚫린 입이라고 함부로 지껄여!?","JPN":"ボケた老いぼれが、勝手なことを言って！","ENG":"You rotten old man, you think you can talk to me like that?!","TWN":"這個該死的老頭，竟敢這麼放肆？！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"납품에 차질이 없길 바란다고?","JPN":"納品の日程に狂いがないことを祈る？","ENG":"Issues on delivering the order?","TWN":"希望交貨不會有任何差池？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"종교학부에서 쫓겨나고 이런 잡일이나 한다고 내가 만만해 보이는 거야!?","JPN":"宗教学部から追い出されてこんな雑務をしてるからって、私を見下してるの！？","ENG":"You think you're better than me because I'm stuck doing this after getting kicked out of the Religion Department?!","TWN":"就因為被宗教學院趕出來，幹這點雜事就覺得我好欺負嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"방금 뭐지……?","JPN":"今のは……？","ENG":"What was that...?","TWN":"剛才那是什麼……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"벽장에서 무슨 소리가 났던 것 같은데?","JPN":"押し入れから音がしたような？","ENG":"I think I heard something from the closet.","TWN":"壁櫥裡好像有什麼聲音？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"테오도라 원장님!","JPN":"テオドラ院長！","ENG":"Ms. Theodora!","TWN":"狄奧朵拉院長！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐야! 내가 보육원에서는 모습을 드러내지 말라고 했잖아!","JPN":"ちょっと！　保育園では姿を見せないようにと言っておいたでしょう！","ENG":"What is it! I told you not to reveal yourself in the orphanage!","TWN":"怎麼回事！我不是說過不要在育幼院裡露面嗎！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"아, 아니 그게…… L-3 구역에서 잔해가 발생했습니다.","JPN":"い、いや、それが……L-3区域で残骸が発生しました。","ENG":"W-well, it's... There's a Remains in Area L-3.","TWN":"不，不是，那個……L-3區出現了殘骸。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"어떻게 할까요?","JPN":"どうしましょう？","ENG":"What should we do?","TWN":"該怎麼處理？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"어떡하긴 뭘 어떡해? 당장 격리 조치해!","JPN":"どうするも何も、今すぐ隔離措置を行いなさい！","ENG":"What do you mean, \\"What should we do?\\" Quarantine it, now!","TWN":"能怎麼處理？馬上隔離起來！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그런데…… 목격자가 있습니다.","JPN":"ですが……目撃者がいます。","ENG":"But... there's a witness.","TWN":"但是……有目擊者。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서, 뭐!? 어차피 그건……!","JPN":"それが何！？　どうせそれは……！","ENG":"So, what?! That doesn't...!","TWN":"所以呢？！反正……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"아니, 내가 너희를 어떻게 믿고. 당장 갈 테니까 현장에서 대기하도록.","JPN":"いいえ、あなたたちは信用できないわ。今すぐ行くから、現場で待機していなさい。","ENG":"No. I can't trust you all. I'll head there right this second. Stand by at the site.","TWN":"算了，我可不相信你們。我馬上過去，在現場等著吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"네, 넵……!","JPN":"は、はい……！","ENG":"O-of course...!","TWN":"好，好的……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이놈이고 저놈이고! 여긴 멀쩡한 놈이 하나도 없어!","JPN":"どいつもこいつも！　役立たずばっかり！","ENG":"Is there anyone around me with a functioning brain?!","TWN":"這裡就沒有一個靠得住的傢伙！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"푸하……!","JPN":"ぷはっ……！","ENG":"Haaah...!","TWN":"噗哈……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"하마터면 들킬 뻔했네!","JPN":"見つかるところだった！","ENG":"She almost caught us!","TWN":"差點被發現了！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"야, 거기서 딸꾹질을 하면…… ","JPN":"ちょっと、今しゃっくりしちゃ…… ","ENG":"Hey, you can't just start hiccupping...","TWN":"喂，你突然打嗝……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이브?","JPN":"イヴ？","ENG":"Eve?","TWN":"伊芙？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"히끅……!","JPN":"ひっく……！","ENG":"*Hiccup...!*","TWN":"嗚嗚……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"흑, 흐으윽……! 히끅! 너무해……!","JPN":"うっ、うううっ……！　ひっく！　ひどい……！","ENG":"Waah...! *Hiccup!* It's so unfair...!","TWN":"嗚，嗚嗚嗚……！嗚嗚！太過分了……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"흐윽, 테오도라 수녀님이 그렇게 화내는 거 처음 봤어.","JPN":"ううっ、テオドラさんがあんなに怒るの、初めて見た。","ENG":"*Sob...* I've never seen Sister Theodora that angry before.","TWN":"嗚嗚，我第一次看到狄奧朵拉修女那麼生氣。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"수녀님은 정말 우리를…… 히끅!","JPN":"テオドラさんは本当に私たちを……ひっく！","ENG":"She really doesn't... *Hiccup!*","TWN":"修女真的要把我們……嗚嗚！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"쯧쯧. 거 봐, 내가 뭐랬냐? 이제 여기서는 아무도 못 믿는다고.","JPN":"チッチッ。ほら、言ったでしょ？　もうここでは誰も信じられないって。","ENG":"Tsk, tsk. See, I told you. You can't trust anyone here.","TWN":"嘖嘖。你看，我怎麼說的？現在這裡的每個人都不能相信了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리 둘 빼고는.","JPN":"私たち二人以外には。","ENG":"Except for you and me.","TWN":"除了我們自己。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"알겠어…… 앤.","JPN":"そうだね……アン。","ENG":"Okay... Ann.","TWN":"我知道了……安妮。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리 여기서 도망치자.","JPN":"私たち、ここから逃げよう。","ENG":"Let's run away.","TWN":"我們逃走吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"대신, 한 가지 부탁할 게 있어.","JPN":"その代わり、一つだけお願いがあるの。","ENG":"But, I have one favor to ask.","TWN":"不過，我想再拜託你一件事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};